4108 /// Reorders the given \p Reuses mask according to the given \p Mask. \p Reuses
4109 /// contains original mask for the scalars reused in the node. Procedure
4110 /// transform this mask in accordance with the given \p Mask.
4111 static void reorderReuses(SmallVectorImpl<int> &Reuses, ArrayRef<int> Mask) {
4112   assert(!Mask.empty() && Reuses.size() == Mask.size() &&
4113          "Expected non-empty mask.");
4114   SmallVector<int> Prev(Reuses.begin(), Reuses.end());
4115   Prev.swap(Reuses);
4116   for (unsigned I = 0, E = Prev.size(); I < E; ++I)
4117     if (Mask[I] != PoisonMaskElem)
4118       Reuses[Mask[I]] = Prev[I];
4119 }
