17652   /// Calculate the cost of a reduction.
17653   InstructionCost getReductionCost(TargetTransformInfo *TTI,
17654                                    ArrayRef<Value *> ReducedVals,
17655                                    bool IsCmpSelMinMax, unsigned ReduxWidth,
17656                                    FastMathFlags FMF) {
17657     TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput;
17658     Type *ScalarTy = ReducedVals.front()->getType();
17659     FixedVectorType *VectorTy = FixedVectorType::get(ScalarTy, ReduxWidth);
17660     InstructionCost VectorCost = 0, ScalarCost;
17661     // If all of the reduced values are constant, the vector cost is 0, since
17662     // the reduction value can be calculated at the compile time.
17663     bool AllConsts = allConstant(ReducedVals);
17664     auto EvaluateScalarCost = [&](function_ref<InstructionCost()> GenCostFn) {
17665       InstructionCost Cost = 0;
17666       // Scalar cost is repeated for N-1 elements.
17667       int Cnt = ReducedVals.size();
17668       for (Value *RdxVal : ReducedVals) {
17669         if (Cnt == 1)
17670           break;
17671         --Cnt;
17672         if (RdxVal->hasNUsesOrMore(IsCmpSelMinMax ? 3 : 2)) {
17673           Cost += GenCostFn();
17674           continue;
17675         }
17676         InstructionCost ScalarCost = 0;
17677         for (User *U : RdxVal->users()) {
17678           auto *RdxOp = cast<Instruction>(U);
17679           if (hasRequiredNumberOfUses(IsCmpSelMinMax, RdxOp)) {
17680             ScalarCost += TTI->getInstructionCost(RdxOp, CostKind);
17681             continue;
17682           }
17683           ScalarCost = InstructionCost::getInvalid();
17684           break;
17685         }
17686         if (ScalarCost.isValid())
17687           Cost += ScalarCost;
17688         else
17689           Cost += GenCostFn();
17690       }
17691       return Cost;
17692     };
